qry:select.qry:xquery:
	for $r in sql('
	SELECT LIQ19_LIQUIDACION.oi_liquidacion,
	LIQ19_LIQUIDACION.c_liquidacion,
	LIQ19_LIQUIDACION.d_titulo			
	FROM LIQ19_LIQUIDACION
	WHERE
	LIQ19_LIQUIDACION.oi_empresa = {#PARAM:@oi_empresa}
	{%? (#PARAM:@e_periodo!='') {% AND LIQ19_LIQUIDACION.e_periodo = {#PARAM:@e_periodo} %} {% %} %}
	{%? (string(#PARAM:LIQUIDACIONES/LIQUIDACION/@id)!='') {% AND LIQ19_LIQUIDACION.oi_liquidacion IN ({%=string(#PARAM:LIQUIDACIONES/LIQUIDACION/@id)%}) %} {% %} %}
	{%? ((#PARAM:@e_periodo='') AND (string(#PARAM:LIQUIDACIONES/LIQUIDACION/@id)='')) {% AND 1=2 %} {% %} %}

')/ROWS/ROW
